#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MOD 747474747
#define MAX_N 6666
#define MAX_D 5

// Define the structure for an edge
typedef struct {
    int u, v;
    long long w;
} Edge;

// Define the structure for the Union-Find data structure
typedef struct {
    int parent[MAX_N];
    int rank[MAX_N];
} UnionFind;

// Function to find the parent of a node in the Union-Find data structure
int find(UnionFind *uf, int x) {
    if (uf->parent[x] != x) {
        uf->parent[x] = find(uf, uf->parent[x]);
    }
    return uf->parent[x];
}

// Function to union two nodes in the Union-Find data structure
void unionNodes(UnionFind *uf, int x, int y) {
    int rootX = find(uf, x);
    int rootY = find(uf, y);
    if (rootX != rootY) {
        if (uf->rank[rootX] < uf->rank[rootY]) {
            uf->parent[rootX] = rootY;
        } else if (uf->rank[rootX] > uf->rank[rootY]) {
            uf->parent[rootY] = rootX;
        } else {
            uf->parent[rootY] = rootX;
            uf->rank[rootX]++;
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, D;
        scanf("%d %d", &N, &D);
        int points[N][D];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < D; j++) {
                scanf("%d", &points[i][j]);
            }
        }
        Edge edges[N * (N - 1) / 2];
        int edgeCount = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                long long distance = 0;
                for (int k = 0; k < D; k++) {
                    distance += (long long)(points[i][k] - points[j][k]) * (points[i][k] - points[j][k]);
                }
                edges[edgeCount].u = i;
                edges[edgeCount].v = j;
                edges[edgeCount].w = distance;
                edgeCount++;
            }
        }
        // Sort the edges in descending order of their weights
        for (int i = 0; i < edgeCount - 1; i++) {
            for (int j = i + 1; j < edgeCount; j++) {
                if (edges[i].w < edges[j].w) {
                    Edge temp = edges[i];
                    edges[i] = edges[j];
                    edges[j] = temp;
                }
            }
        }
        UnionFind uf;
        for (int i = 0; i < N; i++) {
            uf.parent[i] = i;
            uf.rank[i] = 0;
        }
        long long score = 1;
        for (int i = 0; i < edgeCount; i++) {
            if (find(&uf, edges[i].u) != find(&uf, edges[i].v)) {
                unionNodes(&uf, edges[i].u, edges[i].v);
                score = (score * edges[i].w) % MOD;
            }
        }
        printf("%lld\n", score);
    }
    return 0;
}

